window.HK_LC1 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["She is decorating a living room.", "She is adjusting the carpet.", "She is switching off a vacuum.", "She is operating a machine."], "optko": ["그녀는 거실을 장식하고 있다.", "그녀는 카펫을 정돈하고 있다.", "그녀는 진공청소기를 끄고 있다.", "그녀는 기계를 가동하고 있다."], "ans": 3, "audio": "Test01_01.mp3", "img": "hk_t1_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["A man is raising one of his arms.", "A man is getting into a helicopter.", "A man is taking off sunglasses.", "A man is using tools to repair an aircraft."], "optko": ["한 남자가 그의 한 쪽 팔을 들어 올리고 있다.", "한 남자가 헬리콥터에 들어가고 있다.", "한 남자가 선글라스를 벗고 있다.", "한 남자가 항공기를 수리하기 위해 도구를 사용하고 있다."], "ans": 0, "audio": "Test01_02.mp3", "img": "hk_t1_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["They are walking through a forest.", "They are standing next to a trail.", "They are fixing a bike tire.", "They are riding along a path."], "optko": ["그들은 숲을 걷고 있다.", "그들은 오솔길 옆에 서 있다.", "그들은 자전거 타이어를 수리하고 있다.", "그들은 길을 따라 자전거를 타고 있다."], "ans": 3, "audio": "Test01_03.mp3", "img": "hk_t1_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["Oranges are being weighed on a scale.", "A canopy is shading some fruit.", "A vendor is organizing some objects.", "Some stalls are surrounded with shoppers."], "optko": ["오렌지가 저울에서 계량되고 있다.", "천막이 몇몇 과일을 그늘지게 하고 있다.", "상인이 몇몇 물품들을 정리하고 있다.", "몇몇 가판대들이 쇼핑객들로 둘러싸여 있다."], "ans": 1, "audio": "Test01_04.mp3", "img": "hk_t1_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Some brushes are being washed.", "A woman is picking up a canvas.", "Potted plants are being used as decorations.", "A picture is being painted."], "optko": ["붓들이 세척되고 있다.", "한 여자가 캔버스를 들어 올리고 있다.", "화분에 심은 식물들이 장식품으로 사용되고 있다.", "그림이 그려지고 있다."], "ans": 3, "audio": "Test01_05.mp3", "img": "hk_t1_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A canoe is floating down a river.", "Bushes are growing near a stream.", "People are crossing a bridge.", "A waterway is full of debris."], "optko": ["통나무배가 강을 따라 떠내려가고 있다.", "덤불이 강 근처에서 자라고 있다.", "사람들이 다리를 건너고 있다.", "수로가 쓰레기로 가득 차 있다."], "ans": 1, "audio": "Test01_06.mp3", "img": "hk_t1_q6.jpg"}, {"n": 7, "part": 2, "q": "Did you go to the IT convention?", "qko": "당신은 IT 컨벤션에 갔었나요?", "opts": ["It will convene in 5 minutes.", "It's going well.", "No, I was busy."], "optko": ["5분 후에 개최될 거예요.", "잘 되어 가요.", "아니요, 저는 바빴어요."], "ans": 2, "audio": "Test01_07.mp3"}, {"n": 8, "part": 2, "q": "When do you start your new job?", "qko": "당신은 새로운 일을 언제 시작하나요?", "opts": ["At my previous company.", "To sell machinery.", "I'm not sure of the date."], "optko": ["제 이전 회사에서요.", "기계를 판매하기 위해서요.", "날짜가 확실하지 않아요."], "ans": 2, "audio": "Test01_08.mp3"}, {"n": 9, "part": 2, "q": "Why did Lina take a day off yesterday?", "qko": "Lina는 왜 어제 하루를 쉬었나요?", "opts": ["Because it peeled off.", "I think she was here.", "I can take you there."], "optko": ["이게 벗겨졌기 때문이에요.", "저는 그녀가 여기에 있었던 것 같아요.", "제가 당신을 그곳으로 데려다줄 수 있어요."], "ans": 1, "audio": "Test01_09.mp3"}, {"n": 10, "part": 2, "q": "Who's assisting the patient in Room 33?", "qko": "누가 33호실의 환자를 돕고 있나요?", "opts": ["Margaret Peterson.", "A one-hour surgery.", "There are 34, actually."], "optko": ["Margaret Peterson이요.", "한 시간 동안의 수술이요.", "사실, 34개가 있어요."], "ans": 0, "audio": "Test01_10.mp3"}, {"n": 11, "part": 2, "q": "Shouldn't you leave for the training workshop now?", "qko": "당신은 교육 워크숍으로 지금 출발해야 하지 않나요?", "opts": ["He should clean up these leaves.", "They're at the electronics shop.", "Is it 5 o'clock already?"], "optko": ["그는 이 나뭇잎들을 치워야 해요.", "그들은 전자 기기 매장에 있어요.", "벌써 5시인가요?"], "ans": 2, "audio": "Test01_11.mp3"}, {"n": 12, "part": 2, "q": "Did the worker evaluation process go smoothly?", "qko": "직원 평가 과정이 순조롭게 진행되었나요?", "opts": ["For the most part.", "From the Columbus office.", "No, a food processing plant."], "optko": ["대부분은요.", "콜럼버스 지점으로부터요.", "아니요, 식품 가공 공장이요."], "ans": 0, "audio": "Test01_12.mp3"}, {"n": 13, "part": 2, "q": "Weren't these contracts supposed to be signed last week?", "qko": "이 계약서들은 지난주에 서명되기로 되어 있지 않았나요?", "opts": ["Yes, once a week.", "I'll put the sign up right away.", "The clients are on vacation."], "optko": ["네, 일주일에 한 번이요.", "제가 지금 바로 표지판을 세울게요.", "의뢰인들이 휴가 중이에요."], "ans": 2, "audio": "Test01_13.mp3"}, {"n": 14, "part": 2, "q": "Why don't we discuss the budget with Mr. Beacon today?", "qko": "오늘 Mr. Beacon과 예산에 대해 논의하는 게 어때요?", "opts": ["It doesn't need to be finalized until Friday.", "Talks relating to the merger.", "A corporate budget analyst."], "optko": ["그것은 금요일까지 마무리될 필요가 없어요.", "합병과 관련된 논의들이요.", "기업 예산 분석가요."], "ans": 0, "audio": "Test01_14.mp3"}, {"n": 15, "part": 2, "q": "It's clear that my phone isn't charging properly.", "qko": "제 휴대 전화가 충전이 잘 되지 않는 게 확실해요.", "opts": ["I'm not certain who brought them.", "I bet the battery is bad.", "What's the issue with the speaker?"], "optko": ["누가 그것들을 갖고 왔는지 잘 모르겠어요.", "틀림없이 배터리가 안 좋은 걸 거예요.", "스피커의 어떤 점이 문제인가요?"], "ans": 1, "audio": "Test01_15.mp3"}, {"n": 16, "part": 2, "q": "Has the owner of Java Café called back yet?", "qko": "Java Café의 주인이 다시 전화를 주었나요?", "opts": ["I spoke with her a few minutes ago.", "Yes, it's a little cold in here.", "Please use the rear entrance."], "optko": ["제가 몇 분 전에 그녀와 이야기했어요.", "네, 여기는 조금 추워요.", "뒤쪽 입구를 이용해 주세요."], "ans": 0, "audio": "Test01_16.mp3"}, {"n": 17, "part": 2, "q": "Where can I find information about the tour?", "qko": "여행에 대한 정보를 어디에서 찾을 수 있나요?", "opts": ["We discovered more evidence.", "He was informed of the delay.", "Details are on the Web site."], "optko": ["우리는 증거를 더 발견했어요.", "그는 지연에 대해 통지를 받았어요.", "세부 사항은 웹사이트에 있어요."], "ans": 2, "audio": "Test01_17.mp3"}, {"n": 18, "part": 2, "q": "Could you tell me if your spa offers gift certificates?", "qko": "스파가 상품권을 제공하는지 알려주실 수 있나요?", "opts": ["Not as of March.", "Thanks for the voucher.", "A teller will help you with your deposit."], "optko": ["3월부터는 아니에요.", "상품권 감사해요.", "은행 창구 직원이 예금을 도와드릴 거예요."], "ans": 0, "audio": "Test01_18.mp3"}, {"n": 19, "part": 2, "q": "What will be served as the entrée at the awards ceremony?", "qko": "시상식에서 주요리로 무엇이 제공될까요?", "opts": ["Salmon and lemon sauce.", "Service was too slow.", "This job is very rewarding."], "optko": ["연어와 레몬 소스요.", "서비스가 너무 느렸어요.", "이 일은 매우 보람이 있어요."], "ans": 0, "audio": "Test01_19.mp3"}, {"n": 20, "part": 2, "q": "John is a member of the hiring committee, isn't he?", "qko": "John은 고용위원회의 일원이죠, 그렇지 않나요?", "opts": ["I'll hang the poster higher.", "That's the community center.", "I believe so."], "optko": ["제가 포스터를 더 높이 걸게요.", "그건 지역 문화 회관이에요.", "그런 것 같아요."], "ans": 2, "audio": "Test01_20.mp3"}, {"n": 21, "part": 2, "q": "Do you like this desk's color, or should I get something brighter?", "qko": "당신은 이 책상의 색깔이 좋은가요, 아니면 제가 더 밝은 것을 사야 할까요?", "opts": ["It's saved on my desktop computer.", "I think that shade of brown is nice.", "A table for the space would be great."], "optko": ["그건 저의 데스크톱 컴퓨터에 저장되어 있어요.", "저는 이 갈색의 색조가 멋진 것 같아요.", "그 공간에 탁자를 놓으면 매우 좋겠네요."], "ans": 1, "audio": "Test01_21.mp3"}, {"n": 22, "part": 2, "q": "Who painted these landscapes?", "qko": "누가 이 풍경화들을 그렸나요?", "opts": ["One of my art students.", "I'll grab some additional paintbrushes.", "At the Winston Gallery."], "optko": ["제 미술 전공 학생들 중 한 명이요.", "제가 추가로 붓들을 가져올게요.", "Winston 미술관에서요."], "ans": 0, "audio": "Test01_22.mp3"}, {"n": 23, "part": 2, "q": "Why has our parking lot been blocked off?", "qko": "우리 주차장이 왜 차단되어 있나요?", "opts": ["No, park on the road.", "So it can be resurfaced.", "At 2 P.M. today."], "optko": ["아니요, 도로 위에 주차하세요.", "바닥이 재포장될 수 있도록 하기 위해서요.", "오늘 오후 2시에요."], "ans": 1, "audio": "Test01_23.mp3"}, {"n": 24, "part": 2, "q": "Which assignment are you interested in focusing on?", "qko": "어느 업무에 초점을 맞추고 싶으신가요?", "opts": ["Revising the product catalog.", "Sure, let me assign them quickly.", "Mr. Abdul is eager to work here."], "optko": ["상품 카탈로그를 수정하는 것이요.", "물론이죠, 제가 그것들을 빨리 배정할게요.", "Mr. Abdul은 여기에서 일하고 싶어 해요."], "ans": 0, "audio": "Test01_24.mp3"}, {"n": 25, "part": 2, "q": "What are most of the articles in the newsletter about?", "qko": "소식지에 있는 기사들 대부분은 무엇에 관한 건가요?", "opts": ["It's sent out by e-mail.", "Most of them participated.", "Staff achievements."], "optko": ["이것은 이메일로 발송되었어요.", "그들 중 대부분이 참여했어요.", "직원들의 성과요."], "ans": 2, "audio": "Test01_25.mp3"}, {"n": 26, "part": 2, "q": "Is now a good time to take a train ride through the mountains?", "qko": "지금이 산에서 기차 여행을 하기 좋은 시기인가요?", "opts": ["It's beautiful this time of the year.", "The theme park has new rides.", "A view from the mountaintop."], "optko": ["매년 이맘때가 아름다워요.", "테마 공원에 새로운 놀이기구들이 있어요.", "산 정상에서의 전망이요."], "ans": 0, "audio": "Test01_26.mp3"}, {"n": 27, "part": 2, "q": "Don't we have to take down this advertisement banner?", "qko": "우리가 이 광고 배너를 치워야 하지 않나요?", "opts": ["Taking the subway is much faster.", "We're waiting for permission from Ms. Graves.", "No, it doesn't need to be cooked."], "optko": ["지하철을 타는 것이 훨씬 빨라요.", "Ms. Graves의 허가를 기다리고 있어요.", "아니요, 그건 익힐 필요가 없어요."], "ans": 1, "audio": "Test01_27.mp3"}, {"n": 28, "part": 2, "q": "Where did you buy the jacket you're wearing?", "qko": "당신이 입고 있는 재킷을 어디에서 구입했나요?", "opts": ["She's a famous fashion designer.", "The warehouse is closed.", "A boutique in downtown London."], "optko": ["그녀는 유명한 의류 디자이너예요.", "창고는 문을 닫았어요.", "런던 시내의 부티크요."], "ans": 2, "audio": "Test01_28.mp3"}, {"n": 29, "part": 2, "q": "I'm pleased with the progress on the Lila Cosmetics campaign.", "qko": "저는 Lila 화장품사의 캠페인 진행 상황이 마음에 들어요.", "opts": ["It looks good so far, doesn't it?", "Please put it on my desk.", "She's our new campaign manager."], "optko": ["지금까지는 좋아 보여요, 그렇지 않나요?", "제 책상 위에 놓아 주세요.", "그녀는 우리의 새 캠페인 관리자예요."], "ans": 0, "audio": "Test01_29.mp3"}, {"n": 30, "part": 2, "q": "Who's responsible for planning the company picnic?", "qko": "회사 야유회를 계획하는 것을 누가 담당하고 있나요?", "opts": ["I plan to leave around 6 P.M.", "It has been canceled, unfortunately.", "I'd be happy to join you for a picnic!"], "optko": ["저는 오후 6시 정도에 출발할 계획이에요.", "안타깝게도 그건 취소되었어요.", "야유회에 당신과 함께 가고 싶어요!"], "ans": 1, "audio": "Test01_30.mp3"}, {"n": 31, "part": 2, "q": "Will you have your housewarming party indoors or outdoors?", "qko": "집들이 파티를 실내에서 할 건가요, 아니면 야외에서 할 건가요?", "opts": ["Let's see how the weather turns out.", "Of course, I can fix that door.", "It was colder than we expected."], "optko": ["날씨가 어떻게 되는지 봅시다.", "물론이죠, 제가 그 문을 고칠 수 있어요.", "우리가 예상했던 것보다 추웠어요."], "ans": 0, "audio": "Test01_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Ca", "audio": "Test01_32-34.mp3", "qs": [{"n": 32, "q": "Where most likely are the speakers?", "opts": ["In a maintenance office", "In an outdoor market", "In a park", "In a visitor center"], "ans": 2, "ko": "화자들은 어디에 있는 것 같은가?"}, {"n": 33, "q": "According to the woman, what was announced in December?", "opts": ["The renovation of government buildings", "The improvement of public facilities", "The restoration of historic structures", "The opening of recreation areas"], "ans": 1, "ko": "여자에 따르면, 12월에 무엇이 발표되었는가?"}, {"n": 34, "q": "What event will take place next year?", "opts": ["A sports competition", "A local election", "A product launch", "An anniversary party"], "ans": 0, "ko": "내년에 어떤 행사가 개최될 것인가?"}], "script": [{"sp": "W", "en": "Thanks for taking a break from work with me in the park today, Wesley.", "ko": "오늘 업무 중에 저와 함께 공원에서 휴식 시간을 보내줘서 고마워요, Wesley."}, {"sp": "M", "en": "Of course. I didn't realize the plants and grass here are being redone, though.", "ko": "물론이죠. 그런데 이곳의 나무와 잔디를 새로 하는 줄 몰랐어요."}, {"sp": "W", "en": "Yeah. Didn't you hear? City hall officials announced the landscaping work last December. Apparently, it's part of the city's plans to improve our public areas this year.", "ko": "네. 못 들었나요? 시청 공무원이 지난 12월에 조경 작업에 대해 발표했어요. 듣자 하니, 그것은 올해 공공 장소를 개선하기 위한 시의 계획 중 일부라고 해요."}, {"sp": "M", "en": "I see. It must be an effort to get ready for the international soccer tournament taking place in our city next year.", "ko": "그렇군요. 내년에 우리 시에서 열릴 국제 축구 경기를 위해 준비하기 위한 노력임에 틀림없어요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test01_35-37.mp3", "qs": [{"n": 35, "q": "Where most likely do the speakers work?", "opts": ["At a real estate agency", "At a software firm", "At a publishing company", "At an architectural firm"], "ans": 3, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 36, "q": "What does the woman ask about?", "opts": ["A project schedule", "A price list", "A contract change", "A tracking number"], "ans": 0, "ko": "여자는 무엇에 관해 문의하는가?"}, {"n": 37, "q": "Why does the woman say, \"I'm not at my desk right now\"?", "opts": ["She must return to the office.", "She will answer a phone call later.", "She cannot provide some information.", "She must postpone a meeting."], "ans": 2, "ko": "여자는 왜 \"저는 지금 자리에 없어요\"라고 말하는가?"}], "script": [{"sp": "W", "en": "Hello, Hector. I'm just calling to check about the plans you are drafting for the Sanchez Building project. Are you going to be able to complete them before June 10?", "ko": "안녕하세요, Hector. 저는 Sanchez 건물 프로젝트를 위해 당신이 초안을 작성하고 있는 도면들에 관해 좀 확인하려고 전화했어요. 그것들을 6월 10일 전에 완료하실 수 있나요?"}, {"sp": "M", "en": "Actually, I'll require help from our subcontractor for some of the work if you want me to finish before that deadline. Could you give me his phone number so that I can ask him about that?", "ko": "사실, 그 마감 기한 전에 제가 완료하길 원하신다면 일부 작업에 대해 하청업자에게 도움을 요청해야 할 것 같아요. 제가 문의할 수 있도록 그의 전화번호를 주시겠어요?"}, {"sp": "W", "en": "I'm not at my desk right now. I'm going to meet a client, but I can call you back in about an hour and give it to you then.", "ko": "저는 지금 자리에 없어요. 저는 고객을 만나러 가는 길인데 한 시간 안에 다시 전화해서 그걸 당신에게 알려 드릴 수 있어요."}, {"sp": "M", "en": "OK. I'll contact him right after I hear back from you.", "ko": "알겠어요. 당신에게 연락을 받은 후에 바로 그에게 연락할게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 영국식 발음 → 호주식 발음", "audio": "Test01_38-40.mp3", "qs": [{"n": 38, "q": "Where most likely do the speakers work?", "opts": ["At an accommodation facility", "At a tour company", "At a beverage company", "At a car rental agency"], "ans": 1, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 39, "q": "What is mentioned about George Leeland?", "opts": ["He canceled a trip.", "He launched a Web site.", "He gave positive feedback.", "He recruited new workers."], "ans": 2, "ko": "George Leeland에 관해 무엇이 언급되는가?"}, {"n": 40, "q": "What does Fiona say she will do?", "opts": ["Post a safety sign", "Purchase some drinks", "Get some supplies", "Test drive a vehicle"], "ans": 2, "ko": "Fiona는 그녀가 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W1", "en": "Aren't you both pleased that our agency has had more bookings lately?", "ko": "최근 우리 회사에 더 많은 예약들이 들어와서 두 분 다 기쁘지 않으신가요?"}, {"sp": "W2", "en": "Yes. It's probably because we received an outstanding review on famous travel blogger George Leeland's Web page.", "ko": "네. 아마 우리가 유명한 여행 블로거인 George Leeland의 웹페이지에서 우수한 후기를 받았기 때문일 거예요."}, {"sp": "M", "en": "I agree! And that reminds me . . . Is everything ready for the tour that we're leading today?", "ko": "동의해요! 그러고 보니 생각나는데… 우리가 오늘 안내할 여행 준비가 모두 되었나요?"}, {"sp": "W1", "en": "I just stocked the bus with water and snacks. And we've got the safety gear in case any wild animals get too close to the vehicle.", "ko": "저는 방금 버스에 물과 간식을 넣었어요. 그리고 야생동물이 저희 차량에 너무 가까이 올 경우를 대비해 안전 장치를 준비했어요."}, {"sp": "M", "en": "Did you also bring those cans of bug spray we ordered, Fiona?", "ko": "우리가 주문한 살충제들도 가져왔나요, Fiona?"}, {"sp": "W2", "en": "Sorry, no. I'll grab those from our office before we depart.", "ko": "죄송하지만, 아니에요. 출발하기 전에 제가 사무실에서 가져올게요."}, {"sp": "M", "en": "Good. I want to be prepared, since we have our largest group yet today.", "ko": "좋아요. 오늘이 지금까지 가장 큰 규모의 단체이기 때문에 준비가 되어 있기를 원해요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test01_41-43.mp3", "qs": [{"n": 41, "q": "What are the speakers mainly discussing?", "opts": ["Designing a Web site", "Organizing an event", "Visiting a gallery", "Decorating a space"], "ans": 3, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 42, "q": "What does the man mean when he says, \"The opening party was quite impressive\"?", "opts": ["He met an artist.", "He visited a facility.", "He donated some money.", "He completed an assignment."], "ans": 1, "ko": "남자는 \"개관식은 아주 인상적이었어요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 43, "q": "What does the man say he will do?", "opts": ["Store some items", "Talk to an administrator", "Write down an address", "Search for information online"], "ans": 3, "ko": "남자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "I'm considering putting up some new artwork at our hospital. Research shows that patients feel more comfortable at medical facilities with pleasant images displayed.", "ko": "저는 우리 병원에 새로운 그림을 거는 것을 고려하고 있어요. 연구는 기분 좋은 이미지가 전시된 의료 시설에서 환자들이 더 편안하게 느낀다는 것을 보여줘요."}, {"sp": "W", "en": "Have you been to that newly opened gallery downtown . . . umm . . . Westchester Gallery?", "ko": "시내에 새로 문을 연… 음… Westchester 미술관에 가보셨나요?"}, {"sp": "M", "en": "The opening party was quite impressive. But I think the pieces there are too expensive. Do you have any other suggestions?", "ko": "개관식은 아주 인상적이었어요. 하지만 거기에 있는 작품들은 너무 비싼 것 같아요. 다른 제안이 있으세요?"}, {"sp": "W", "en": "Jesse's Home Goods has some reasonably priced works. That store is located two blocks down from our building, actually.", "ko": "Jesse's 가정용품점에 합리적으로 값이 매겨진 작품들이 있어요. 사실, 그 상점은 저희 건물에서 두 블록 아래에 위치해 있었어요."}, {"sp": "M", "en": "I've never heard of that place. I'll check its Web site now and see what it has available.", "ko": "저는 그곳에 대해 들어본 적이 없어요. 지금 웹사이트를 확인하고 그곳에 구매할 수 있는 게 뭐가 있는지 확인해 볼게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test01_44-46.mp3", "qs": [{"n": 44, "q": "Why is the man calling the woman?", "opts": ["To conduct an interview", "To inquire about a document", "To confirm travel plans", "To promote a product"], "ans": 1, "ko": "남자는 왜 여자에게 전화를 하고 있는가?"}, {"n": 45, "q": "What does the man offer to do?", "opts": ["Organize a business trip", "Arrange a public event", "Revise an itinerary", "Provide a discount"], "ans": 3, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}, {"n": 46, "q": "What does the woman say will happen this Friday?", "opts": ["Her colleague will come back.", "Her salary will be increased.", "She will receive some coupons.", "She will hire a consultant."], "ans": 0, "ko": "여자는 이번 주 금요일에 무슨 일이 일어날 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "Ms. Pennington, this is Carl from Northwood Marketing. I'm calling to see if you've had a chance to review the contract I sent you. The one for the public relations services you inquired about . . .", "ko": "Ms. Pennington, 저는 Northwood 마케팅사의 Carl입니다. 제가 보내드렸던 계약서를 검토할 기회가 있으셨는지 확인하고자 전화드렸습니다. 당신이 문의하신 홍보 서비스에 관한 것이요…"}, {"sp": "W", "en": "Yes. But I think the rate you want to charge is too high. The last PR contractor I hired had lower fees.", "ko": "네. 하지만 당신이 청구하고자 하는 요금이 너무 높은 것 같아요. 제가 고용했던 지난 홍보 하청업자는 요금이 더 낮았거든요."}, {"sp": "M", "en": "I understand. Since I was referred to you by another client, I can give you a 10 percent service fee reduction.", "ko": "알겠습니다. 다른 고객 분이 당신에게 저를 소개해주셨기 때문에, 10퍼센트의 서비스 요금 할인을 제공해드릴 수 있습니다."}, {"sp": "W", "en": "That sounds reasonable. However, I'll need to consult with my company's financial manager first, and he's currently traveling overseas. He'll return this Friday, so I'll call you then.", "ko": "적정한 것 같네요. 하지만, 저희 회사의 재무 관리자와 먼저 상의해야 하는데, 그가 현재 해외 여행 중이에요. 그가 이번 주 금요일에 돌아올 거니까, 그때 전화드릴게요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test01_47-49.mp3", "qs": [{"n": 47, "q": "Where is the conversation most likely taking place?", "opts": ["At a dry-cleaning service", "At a manufacturing plant", "At an appliance store", "At an apartment building"], "ans": 3, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 48, "q": "What did the man's colleague forget to do?", "opts": ["Fix a machine", "Exchange an item", "Unlock a door", "Pay a fee"], "ans": 2, "ko": "남자의 동료는 무엇을 하는 것을 잊었는가?"}, {"n": 49, "q": "What does the man tell the woman to do?", "opts": ["Wait for a phone call", "Enter an account password", "Contact a manager", "Visit an office"], "ans": 0, "ko": "남자는 여자에게 무엇을 하라고 말하는가?"}], "script": [{"sp": "W", "en": "Good morning. This is the tenant from Unit 504 calling. Umm . . . our building's common laundry room has been locked since this morning. When will it be opened?", "ko": "안녕하세요. 504호에서 전화드리는 세입자입니다. 음… 오늘 아침부터 저희 건물의 공동 세탁실이 잠겨 있었어요. 언제 열리나요?"}, {"sp": "M", "en": "I'm so sorry. I didn't realize that. My colleague probably forgot to unlock the door this morning. She has the key but is giving a tour to a new tenant right now. She'll be back in 10 minutes, though.", "ko": "정말 죄송합니다. 제가 그걸 몰랐네요. 제 동료가 아마 오늘 아침에 문을 여는 것을 잊어버린 것 같아요. 그녀가 열쇠를 갖고 있지만 지금 새로운 세입자에게 안내를 해드리고 있어요. 하지만, 10분 후에 돌아올 거예요."}, {"sp": "W", "en": "OK. But I need to do laundry soon because I'm leaving on a business trip this evening.", "ko": "알겠어요. 하지만 저는 오늘 저녁에 출장을 가기 때문에 곧 빨래를 해야 해요."}, {"sp": "M", "en": "Please wait upstairs for just a little while longer. I'll call you back as soon as she gets here.", "ko": "위층에서 조금만 더 기다려주세요. 그녀가 여기 도착하자마자 다시 전화드릴게요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test01_50-52.mp3", "qs": [{"n": 50, "q": "What type of event is taking place?", "opts": ["A social gathering", "A product demonstration", "A furniture sale", "A food exposition"], "ans": 0, "ko": "어떤 종류의 행사가 일어나고 있는가?"}, {"n": 51, "q": "What does the woman say she needs to do?", "opts": ["Remodel a kitchen", "Put out some refreshments", "Send some invitations", "Contact a retailer"], "ans": 1, "ko": "여자는 무엇을 해야 한다고 말하는가?"}, {"n": 52, "q": "What will the man most likely do next?", "opts": ["Give a recommendation", "Read a pamphlet", "Order a sofa", "Browse a Web site"], "ans": 1, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Good afternoon, Lesley. Thank you so much for inviting me to your housewarming party.", "ko": "안녕하세요, Lesley. 저를 집들이에 초대해주셔서 정말 감사해요."}, {"sp": "W", "en": "I'm glad you made it. You're actually the first person here, so please have a seat anywhere in the living room. I still need to bring out the snacks and drinks from the kitchen.", "ko": "와주셔서 기쁘네요. 사실 당신이 여기 첫 번째로 오셨으니 거실 아무 데나 앉으시면 돼요. 저는 아직 부엌에서 간식과 음료를 가져와야 해요."}, {"sp": "M", "en": "Great . . . Wow! This space is decorated very nicely. Where did you buy this sofa?", "ko": "좋아요… 우아! 이 공간은 정말 잘 꾸며져 있네요. 이 소파는 어디에서 사셨어요?"}, {"sp": "W", "en": "From a vintage furniture retailer downtown. I have one of the store's brochures right here, if you're interested.", "ko": "시내에 있는 빈티지 가구 소매점에서요. 그 상점의 책자 중 하나가 바로 여기 있어요, 관심 있으시다면요."}, {"sp": "M", "en": "OK. I'll look through this while I wait for everyone else to arrive.", "ko": "좋아요. 다른 사람들이 도착하길 기다리는 동안 이것을 살펴보고 있을게요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test01_53-55.mp3", "qs": [{"n": 53, "q": "What does the man tell the woman to do?", "opts": ["Post some safety notices", "Visit a manager's office", "Take part in a group call", "Distribute some documents"], "ans": 2, "ko": "남자는 여자에게 무엇을 하라고 말하는가?"}, {"n": 54, "q": "What does the woman ask the man about?", "opts": ["A meeting agenda", "A travel itinerary", "A schedule change", "A project timetable"], "ans": 0, "ko": "여자는 남자에게 무엇에 관해 문의하는가?"}, {"n": 55, "q": "What does the man say about the conference room?", "opts": ["It will be locked tomorrow.", "It is in a convention center.", "It contains a computer.", "It will be renovated."], "ans": 2, "ko": "남자는 회의실에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "I have to go to one of our warehouses to conduct a safety inspection. Can you please join this afternoon's management conference call and take notes for me?", "ko": "저는 안전 검사를 하기 위해 저희 창고들 중 한 곳에 가야 해요. 오늘 오후에 경영진 전화 회의에 참여해서 저를 위해 메모를 해주실 수 있나요?"}, {"sp": "W", "en": "No problem. Will the managers be discussing the new distribution center?", "ko": "문제 없어요. 경영진들이 새로운 유통 센터에 대해 논의할 건가요?"}, {"sp": "M", "en": "I don't believe so. They'll likely talk about productivity issues at the Atlanta plant. But if they mention the construction project, please tell them I'll provide a status update on that by e-mail tomorrow.", "ko": "아닐 거예요. 그들은 애틀랜타 공장의 생산성 문제에 대해 이야기할 것 같아요. 하지만 그들이 건설 프로젝트에 대해 언급하면, 제가 내일 이메일로 그것에 대한 상황 업데이트를 제공할 것이라고 말해주세요."}, {"sp": "W", "en": "OK. The call starts at 2 P.M., right?", "ko": "알겠어요. 통화는 오후 2시에 시작하죠, 맞나요?"}, {"sp": "M", "en": "Yes. I reserved the second-floor conference room for you at that time. It has a laptop that you can use.", "ko": "네. 당신을 위해 그 시간에 2층 회의실을 예약해 두었어요. 사용하실 수 있는 노트북 컴퓨터가 있거든요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test01_56-58.mp3", "qs": [{"n": 56, "q": "Why was the woman unable to meet the man yesterday?", "opts": ["Her car was being repaired.", "She watched a sports match.", "Her family was visiting.", "She joined a city tour."], "ans": 2, "ko": "여자는 왜 어제 남자를 만날 수 없었는가?"}, {"n": 57, "q": "What is mentioned about Gamer's Trail?", "opts": ["It runs alongside a waterway.", "It is designed for beginners.", "It is closed for the weekend.", "It connects two city parks."], "ans": 0, "ko": "Gamer's 코스에 관해 무엇이 언급되는가?"}, {"n": 58, "q": "What can the man's friend do?", "opts": ["Research trails", "Buy a map", "Make a reservation", "Provide transportation"], "ans": 3, "ko": "남자의 친구는 무엇을 할 수 있는가?"}], "script": [{"sp": "W", "en": "Sorry I couldn't hang out with you yesterday. My parents stayed at my place over the weekend, and we went for a hike together.", "ko": "어제 함께 시간을 보내지 못해서 미안해요. 저희 부모님이 주말 동안 저희 집에 계속 계셨고, 저희는 함께 도보 여행을 했거든요."}, {"sp": "M", "en": "That's fine. They live far away, don't they?", "ko": "괜찮아요. 그들은 멀리 사시죠, 그렇지 않나요?"}, {"sp": "W", "en": "Yeah, so it was good to see them.", "ko": "네, 그래서 볼 수 있어서 좋았어요."}, {"sp": "M", "en": "Where did you end up hiking yesterday, by the way?", "ko": "그런데, 어제 어디에서 도보 여행을 하게 되었어요?"}, {"sp": "W", "en": "Gamer's Trail, which I had never been to before. It follows Bend River from downtown. I think you'd really enjoy the hike. Why don't we go there together sometime?", "ko": "Gamer's 코스인데, 제가 전에 한 번도 안 가본 곳이에요. 그것은 시내에서부터 Bend강을 따라 나 있어요. 당신도 정말 즐겁게 도보 여행을 하실 것 같아요. 언제 같이 가는 어때요?"}, {"sp": "M", "en": "Sure. In fact, one of my friends mentioned he wants to try out that trail. And he just bought a new car. So, if you want, we can all drive there together.", "ko": "물론이죠. 사실, 제 친구들 중 한 명이 그 길을 가보고 싶다고 했었어요. 그리고 그는 막 새 차를 샀거든요. 그래서 원하시면, 다함께 그곳으로 드라이브할 수 있을 거예요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W1-Am / W2-Br", "audio": "Test01_59-61.mp3", "qs": [{"n": 59, "q": "What does the man ask about?", "opts": ["Preparations for an upcoming event", "Revisions to an employee handbook", "Decisions about a training program", "Qualifications of a recent hire"], "ans": 0, "ko": "남자는 무엇에 관해 문의하는가?"}, {"n": 60, "q": "Why does Sarah apologize?", "opts": ["She printed insufficient copies of a manual.", "She notified the wrong staff member.", "She could not attend an orientation.", "She did not complete a task."], "ans": 3, "ko": "Sarah는 왜 사과하는가?"}, {"n": 61, "q": "What will happen this afternoon?", "opts": ["A report will be submitted.", "An evaluation will be conducted.", "A presentation will be given.", "A system will be updated."], "ans": 2, "ko": "오늘 오후에 무슨 일이 일어날 것인가?"}], "script": [{"sp": "M", "en": "Is everything ready for the employee orientation tomorrow? The one for the new staff members joining the finance team . . .", "ko": "내일 직원 오리엔테이션을 위한 모든 준비가 되었나요? 재무팀에 합류하는 새로운 직원들을 위한 거요…"}, {"sp": "W1", "en": "I think so. I've updated all of the training materials. And Sarah said she would print out copies of the employee manual for everyone.", "ko": "그런 것 같아요. 저는 모든 교육 자료를 업데이트했어요. 그리고 Sarah가 모두를 위한 직원 안내서를 출력할 것이라고 말했어요."}, {"sp": "W2", "en": "I'm sorry, but I haven't had a chance to do that. I've been really busy lately.", "ko": "죄송하지만, 제가 그걸 할 기회가 없었어요. 제가 최근에 정말 바빴거든요."}, {"sp": "M", "en": "Oh, I heard you were asked to give a presentation on the new evaluation system.", "ko": "아, 당신이 새로운 평가 시스템에 대해 발표하도록 요청받았다고 들었어요."}, {"sp": "W2", "en": "That's right. It's at 3 P.M. today, and I still have a lot to prepare.", "ko": "맞아요. 발표가 오늘 오후 3시에 있는데, 아직 준비할 게 많아요."}, {"sp": "W1", "en": "Then don't worry about the manuals. I can get them printed before I go for lunch.", "ko": "그러면 안내서에 대해서는 걱정하지 마세요. 제가 점심 먹으러 가기 전에 출력할 수 있어요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "W-Am / M-Cn", "audio": "Test01_62-64.mp3", "qs": [{"n": 62, "q": "What does the woman say she will do?", "opts": ["Rent a car", "Visit a museum", "Rate a hotel", "Upgrade a room"], "ans": 1, "ko": "여자는 무엇을 할 것이라고 말하는가?"}, {"n": 63, "q": "Look at the graphic. What hotel will the woman most likely prefer?", "opts": ["Grassfield Inn", "Golden Column Hotel", "Rose Garden Hotel", "Pressford Inn"], "ans": 2, "ko": "시각 자료를 보시오. 여자는 어떤 호텔을 선호할 것 같은가?"}, {"n": 64, "q": "What will the man probably do next?", "opts": ["Process a payment", "Check room availability", "Issue a receipt", "Request booking confirmation"], "ans": 1, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Hello. I'm looking to reserve a standard hotel room for my vacation in Sacramento. I plan to go to the National Art Museum and want to stay nearby, as I won't be renting a car.", "ko": "안녕하세요. 저는 새크라멘토에서의 휴가를 위해 호텔의 일반 객실을 예약하려고 생각하고 있어요. 제가 국립 미술관에 갈 계획인데, 차를 빌리지 않을 거라서 근처에 머물고 싶어요."}, {"sp": "M", "en": "OK. Have you considered the Golden Column Hotel? It is $125 per night and has a five-star rating on most hotel review sites.", "ko": "알겠습니다. Golden Column 호텔을 고려해보셨나요? 1박당 125달러이고 대부분의 호텔 후기 사이트에서 별 다섯 개의 평점을 받습니다."}, {"sp": "W", "en": "That's rather expensive. I'd prefer something under $100 per night that has at least a four-star rating. Do you know of any establishments like that?", "ko": "꽤 비싸네요. 저는 적어도 별 네 개의 평점을 받으면서, 1박당 100달러 미만인 것을 선호해요. 그런 시설을 알고 계신가요?"}, {"sp": "M", "en": "Hmm . . . There is one, but I need to see if any rooms are available. I'll phone there now. Um, when are you planning to come to Sacramento?", "ko": "흠… 하나 있지만, 이용 가능한 객실이 있는지 확인해야 합니다. 제가 지금 전화해보겠습니다. 음, 새크라멘토에 언제 올 계획이신가요?"}], "gimg": "hk_t1_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "W-M", "audio": "Test01_65-67.mp3", "qs": [{"n": 65, "q": "What did the man do two days ago?", "opts": ["Read a manual", "Requested a refund", "Made a purchase", "Received a delivery"], "ans": 2, "ko": "남자는 이틀 전에 무엇을 했는가?"}, {"n": 66, "q": "Look at the graphic. Which battery type will the man most likely buy?", "opts": ["CR927", "CR1025", "CR1216", "CR1220"], "ans": 3, "ko": "시각 자료를 보시오. 남자는 어떤 배터리 종류를 살 것 같은가?"}, {"n": 67, "q": "What will the woman probably do next?", "opts": ["Restock a shelf", "Change some batteries", "Demonstrate a device", "Locate some items"], "ans": 3, "ko": "여자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Welcome to Fitzroy Gadgets. Can I help you with anything?", "ko": "Fitzroy Gadgets에 오신 것을 환영합니다. 무엇을 도와드릴까요?"}, {"sp": "M", "en": "Yes. I bought a digital scale here two days ago. When I got home and opened the package, I noticed that the scale doesn't come with batteries. I haven't looked at the manual yet, so I'm not sure of the exact type of battery I need.", "ko": "네. 제가 이틀 전에 여기서 디지털 저울을 샀어요. 제가 집에 가서 상자를 열었을 때, 저울에 배터리가 딸려 있지 않은 것을 발견했어요. 제가 아직 설명서를 보지 않아서, 필요한 배터리의 정확한 종류는 모르겠어요."}, {"sp": "W", "en": "That's not an issue. I have a list of the battery types for all of the devices we sell. Uh, which digital scale model did you buy?", "ko": "그건 문제가 아니에요. 저희가 파는 모든 기기의 배터리 종류 목록을 가지고 있습니다. 어, 어떤 디지털 저울 모델을 구입하셨나요?"}, {"sp": "M", "en": "Um, the Ollie 500...", "ko": "음, Ollie 500이요…"}, {"sp": "W", "en": "Great. We have batteries for that one in stock. I'll help you find them now.", "ko": "좋아요. 저희에게 그것의 배터리 재고가 있네요. 지금 찾는 것을 도와드릴게요."}], "gimg": "hk_t1_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-W", "audio": "Test01_68-70.mp3", "qs": [{"n": 68, "q": "Where do the speakers most likely work?", "opts": ["At a catering business", "At a taxi service", "At a moving company", "At a marketing firm"], "ans": 0, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 69, "q": "What is mentioned about Mr. Bauer?", "opts": ["He is a longtime client.", "He is a government employee.", "He is taking a business trip.", "He is planning a dinner party."], "ans": 2, "ko": "Mr. Bauer에 관해 무엇이 언급되는가?"}, {"n": 70, "q": "Look at the graphic. When will the speakers most likely arrive at Ms. Lim's office?", "opts": ["At 9 A.M.", "At 12 P.M.", "At 1 P.M.", "At 4 P.M."], "ans": 2, "ko": "시각 자료를 보시오. 화자들은 Ms. Lim의 사무실에 언제 도착할 것 같은가?"}], "script": [{"sp": "M", "en": "Fumiko, Ms. Lim is planning a party on Wednesday, April 4 and would like our company to provide the food. But I checked the schedule, and we are fully booked that day.", "ko": "Fumiko, Ms. Lim이 4월 4일 수요일에 파티를 계획 중인데 우리 회사에서 요리를 제공하기를 원하세요. 하지만 제가 일정표를 확인했는데, 그날 예약이 다 차 있어요."}, {"sp": "W", "en": "Actually, Mr. Bauer from Hasbo Industrial just canceled his corporate luncheon. I guess he is flying to Spain that week to meet with an important client. I haven't had a chance to update the schedule yet.", "ko": "사실, Hasbo Industrial사의 Mr. Bauer가 방금 그의 기업 오찬을 취소했어요. 그가 그 주에 중요한 고객을 만나러 스페인에 가는 것 같아요. 아직 스케줄을 업데이트 하지는 못했어요."}, {"sp": "M", "en": "Really? In that case, I will call Ms. Lim now and let her know we can accommodate her on that day. This works well for us... Her office is close to the Guraya Communications complex. We won't have to travel far once Ms. Lim's party has finished.", "ko": "정말이요? 그렇다면, 지금 Ms. Lim에게 전화해서 그날 서비스를 공급할 수 있다고 알려드릴게요. 저희에게 잘 되어 가네요… 그녀의 사무실은 Guraya Communications사 복합 건물과 가까워요. Ms. Lim의 파티가 끝나고 멀리 이동하지 않아도 될 거예요."}], "gimg": "hk_t1_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test01_71-73.mp3", "qs": [{"n": 71, "q": "What is being advertised?", "opts": ["A hotel booking application", "A new luxury resort", "A tour guide association", "An online clothing store"], "ans": 0, "ko": "무엇이 광고되고 있는가?"}, {"n": 72, "q": "How can listeners earn a discount?", "opts": ["By filling out a questionnaire", "By recommending a company to friends", "By posting a customer review", "By using a service multiple times"], "ans": 3, "ko": "청자들은 어떻게 할인을 받을 수 있는가?"}, {"n": 73, "q": "Why should listeners visit a Web site?", "opts": ["To view an itinerary", "To become a member", "To look at some images", "To calculate reward points"], "ans": 1, "ko": "청자들은 왜 웹사이트를 방문해야 하는가?"}], "script": [{"sp": "M", "en": "Do you expect only the highest-quality accommodations when you travel? Then join GOFAR and become part of an exclusive club. Our online application finds the best deals on rooms in five-star establishments on your behalf. Our GOFAR loyalty program will also let you accumulate points and earn a major discount after you book through us 10 times. So go to www.gofarapp.com, where you can fill out a membership form in less than 10 minutes! Once you do, you can download our application and begin discovering amazing deals.", "ko": "여행을 할 때 최고급의 숙소만을 기대하십니까? 그렇다면 GOFAR에 가입하시고 회원제 클럽의 일원이 되십시오. 저희의 온라인 애플리케이션은 여러분을 대신하여 5성급 호텔의 객실들에 대한 특가들을 찾아드립니다. 또한 저희의 GOFAR 로열티 프로그램은 포인트를 쌓을 수 있게 해주며 저희를 통해 열 번 예약을 하신 후에는 주요 할인을 받을 수 있도록 해드립니다. 그러니 10분 이내에 회원 신청서를 작성하실 수 있는 www.gofarapp.com으로 가세요! 그렇게 하시면, 저희의 애플리케이션을 다운로드 받을 수 있고 엄청난 특가 상품을 발견하기 시작할 수 있습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "M-Am", "audio": "Test01_74-76.mp3", "qs": [{"n": 74, "q": "Where does the speaker most likely work?", "opts": ["At a university", "At a print shop", "At a history museum", "At an architectural firm"], "ans": 3, "ko": "화자는 어디에서 일하는 것 같은가?"}, {"n": 75, "q": "What is the speaker most likely excited about?", "opts": ["Being honored at an award ceremony", "Visiting a new interactive exhibit", "Finishing a proposal on time", "Getting selected for a job"], "ans": 3, "ko": "화자는 무엇에 들떠 있는 것 같은가?"}, {"n": 76, "q": "Why does the speaker say, \"the schedule is going to be tight\"?", "opts": ["To suggest that a deadline will be extended", "To request assistance with a new project", "To provide a reason for a temporary policy", "To explain why additional staff will be hired"], "ans": 2, "ko": "화자는 왜 \"일정이 빠듯할 것입니다\"라고 말하는가?"}], "script": [{"sp": "M", "en": "I'd like to thank everyone for coming in early this morning. I have a big announcement to make. Our blueprints for the history museum have been chosen, although a lot of other award-winning firms submitted proposals. This is quite an achievement! Construction is set to begin in July, and our company will be teaming up with a contracting company to carry out the work. However, the schedule is going to be tight. Therefore, no leave requests will be granted during July, August, or September. It's the only way we can ensure that we are adequately staffed for the project.", "ko": "오늘 아침 일찍 와주신 것에 대해 여러분 모두에게 감사드리고 싶습니다. 중요한 발표 사항이 있습니다. 수상 경력이 있는 많은 다른 회사들이 제안을 제출했음에도 불구하고, 역사 박물관에 대한 우리의 청사진이 선정되었습니다. 이것은 상당한 성과입니다! 건설 공사는 7월에 시작할 예정이고, 우리 회사는 작업을 실행하기 위해 계약을 맺은 회사와 협력을 할 것입니다. 그러나, 일정이 빠듯할 것입니다. 따라서, 7월, 8월, 또는 9월 동안에는 휴가 신청이 승인되지 않을 것입니다. 이것이 우리가 프로젝트를 위해 충분히 직원을 제공하도록 하는 유일한 방법입니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test01_77-79.mp3", "qs": [{"n": 77, "q": "What kind of business is Firstgrade?", "opts": ["A technology firm", "A grocery store", "A shipping company", "A financial institution"], "ans": 1, "ko": "Firstgrade는 어떤 종류의 사업체인가?"}, {"n": 78, "q": "Why do customers like a new business concept?", "opts": ["It reduces waste.", "It saves money.", "It improves people's health.", "It takes less time."], "ans": 1, "ko": "고객들은 왜 새로운 사업 콘셉트를 좋아하는가?"}, {"n": 79, "q": "What will probably happen next month?", "opts": ["A strategy will be used in more stores.", "A final testing period will get underway.", "A new executive will be named.", "A start-up company will be bought."], "ans": 0, "ko": "다음 달에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "Welcome to RWV FM's Business News Break. Health food retail chain Firstgrade has just posted strong quarterly earnings, proving that their new business model is highly popular with shoppers. The model allows customers to bring in their own containers for certain bulk staples such as rice and beans, which reduces the cost. The retailer itself buys those items in large containers, increasing its own margins. The implementation of this successful business idea is expected to go nationwide starting next month.", "ko": "RWV FM의 Business News Break에 오신 것을 환영합니다. 건강 음식 소매 체인점인 Firstgrade가 그들의 새로운 사업 모델이 쇼핑객들에게 매우 인기가 있음을 보여주는 확고한 분기별 수익을 게시했습니다. 그 모델은 고객들이 쌀과 콩 같은 특정 대용량의 기본 식료품들에 대해 자신들의 용기를 가지고 오도록 하는데, 이것이 비용을 줄이게 합니다. 소매상은 이러한 물품들을 대형 용기들로 구매하여 그들의 이윤을 늘립니다. 이 성공적인 사업 아이디어의 시행은 다음 달부터 전국적으로 확대될 예정입니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test01_80-82.mp3", "qs": [{"n": 80, "q": "What is the main topic of the meeting?", "opts": ["A budgeting decision", "A retirement party", "A position opening", "A software launch"], "ans": 2, "ko": "회의의 주제는 무엇인가?"}, {"n": 81, "q": "What does the speaker recommend doing?", "opts": ["Sending a message", "Attending a celebration", "Reviewing some information", "Giving some presentations"], "ans": 0, "ko": "화자는 무엇을 하라고 제안하는가?"}, {"n": 82, "q": "According to the speaker, what will Ms. West do next Friday?", "opts": ["Make another announcement", "Begin a new role", "Interview some candidates", "Share some findings"], "ans": 2, "ko": "화자에 따르면, Ms. West는 다음 주 금요일에 무엇을 할 것인가?"}], "script": [{"sp": "M", "en": "For those who haven't heard yet, our senior software engineer Mr. Seymour will be retiring on November 29, and we still have yet to find a replacement. Our company's management team has informed me that they'd prefer to hire someone from within our division. So if you're interested, you should send an e-mail to our chief technology supervisor, Marilyn West, stating why you'd be a good fit for this position. Ms. West will . . . ah . . . begin conducting interviews on November 10, which is next Friday. So, it would be best to act quickly. OK. That's all for now.", "ko": "아직 듣지 못하신 분들을 위해, 우리의 선임 소프트웨어 엔지니어인 Mr. Seymour가 11월 29일에 은퇴를 할 것이며, 우리는 아직 후임자를 찾지 못했습니다. 우리 회사 경영진은 우리 부서 내에서 누군가를 고용하는 것을 선호한다고 제게 통지했습니다. 따라서 관심이 있으시다면, 우리의 최고 기술 책임자인 Marilyn West에게 왜 당신이 이 자리에 알맞은 사람인지 설명하는 이메일을 보내주십시오. Ms. West는… 아… 다음 주 금요일인 11월 10일에 인터뷰를 시작할 것입니다. 그러니, 서두르는 게 좋을 것입니다. 좋아요, 지금은 이게 전부입니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test01_83-85.mp3", "qs": [{"n": 83, "q": "What is the message mainly about?", "opts": ["Hiring an electrician", "Relocating some employees", "Installing new office computers", "Organizing a conference"], "ans": 1, "ko": "메시지는 주로 무엇에 관한 것인가?"}, {"n": 84, "q": "Why does the speaker say, \"it is one large room\"?", "opts": ["To confirm a reservation", "To state a preference", "To indicate a concern", "To turn down an offer"], "ans": 2, "ko": "화자는 왜 \"그것은 하나의 큰 방이에요\"라고 말하는가?"}, {"n": 85, "q": "What does the speaker say will happen on Monday?", "opts": ["Some repairs will begin.", "Some workers will leave early.", "A delivery will be sent out.", "A space will be painted."], "ans": 0, "ko": "화자는 월요일에 무슨 일이 있을 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "Kim, it's Ann Jennings. There's going to be an electrician fixing some of the wiring on the fourth floor all next week. The work will likely be loud and distracting, so I've arranged for everyone stationed in that area to work in the conference room on the sixth floor. Just one thing—it is one large room. This will only last the week, however, so I hope people will understand. Also, feel free to collect your laptop and anything else you might need from your office on Monday morning as the electrician won't start until around 10 A.M.", "ko": "Kim, Ann Jennings예요. 다음 주 내내 4층의 배선 일부를 수리할 전기 기술자가 올 거예요. 그 작업이 시끄럽고 소란스러울 것 같아서 그 구역에 배치되어 있는 모든 사람들이 6층에 있는 회의실에서 일할 수 있도록 마련해두었어요. 다만 한 가지, 그것은 하나의 큰 방이에요. 하지만, 이것은 일주일 동안만 지속될 예정이니 사람들이 부디 이해해주길 바라요. 또한, 전기 기술자는 오전 10시나 되어야 시작할 테니 월요일 아침에 당신의 사무실에서 노트북과 필요한 것들을 자유롭게 가져오도록 하세요."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test01_86-88.mp3", "qs": [{"n": 86, "q": "According to the speaker, what did the listener recently do?", "opts": ["Downloaded some documents", "Edited some Web pages", "Scheduled a tour of a headquarters", "Took pictures of a product"], "ans": 3, "ko": "화자에 따르면, 청자는 최근에 무엇을 했는가?"}, {"n": 87, "q": "What is mentioned about a request?", "opts": ["It was written down.", "It came from an intern.", "It will be announced soon.", "It was not fulfilled."], "ans": 3, "ko": "요청에 관해 무엇이 언급되는가?"}, {"n": 88, "q": "Why should the listener contact the speaker?", "opts": ["To discuss some rates", "To recommend a company", "To provide an update", "To postpone a visit"], "ans": 2, "ko": "청자는 왜 화자에게 연락해야 하는가?"}], "script": [{"sp": "W", "en": "Hello. This is Wanda Cruz from FizzPop. I'm calling for Randy Mines. You recently came to our headquarters to take promotional photographs of our Grape RefreshUp soda, which we plan to use on our various social media pages. There's a slight issue, however. Although we requested close-up shots of the can, none are included in the files you sent us. I'm not sure if you forgot to e-mail them or if they were never taken. I'll look forward to hearing back from you about this. Thanks.", "ko": "안녕하세요. FizzPop의 Wanda Cruz입니다. 저는 Randy Mines와 통화하려고 전화드렸습니다. 당신은 저희가 다양한 소셜미디어 페이지에 이용할 계획인 Grape RefreshUp 음료의 홍보 사진을 촬영하기 위해 최근에 저희 본사에 오셨습니다. 하지만, 약간의 문제가 있습니다. 저희가 캔의 근접 촬영을 요청했지만 당신이 보내주신 파일에는 전혀 포함되어 있지 않습니다. 당신이 그것들을 이메일로 보내는 것을 잊으셨는지, 아니면 촬영조차 되지 않았는지 모르겠습니다. 이에 대해서 당신의 연락을 기다리고 있겠습니다. 감사합니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test01_89-91.mp3", "qs": [{"n": 89, "q": "Who are the listeners?", "opts": ["Potential investors", "Stage performers", "Award winners", "Financial donors"], "ans": 3, "ko": "청자들은 누구인가?"}, {"n": 90, "q": "When will ticket prices be reduced?", "opts": ["In January", "In February", "In August", "In September"], "ans": 2, "ko": "티켓 가격은 언제 인하될 것인가?"}, {"n": 91, "q": "What will the speaker probably do next?", "opts": ["Introduce an important figure", "Distribute some programs", "Show people around a facility", "Explain a seating arrangement"], "ans": 2, "ko": "화자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Hello, everybody. When the Chestnut Theater closed last January due to poor attendance levels, it was a huge disappointment for many residents. However, thanks to the generous contributions of you and other community members, we were able to build this new, smaller theater, Victoria Playhouse. To mark the occasion, performances in August—our first month in operation—will be discounted. And season passes will be sold for just $75 during this time. Now, if you'll follow me, I'd be happy to provide a brief tour of the stage and backstage areas.", "ko": "안녕하세요, 여러분. Chestnut 극장이 지난 1월 낮은 관객 수로 인해 문을 닫았을 때, 그것은 많은 주민들에게 큰 실망을 안겨주었습니다. 그러나, 여러분과 다른 지역 사회의 구성원들의 아낌없는 기부 덕분에 이 새롭고 더 아담한 극장인 Victoria Playhouse를 세울 수 있었습니다. 이 행사를 기념하기 위해 운영 첫 달인 8월의 공연들이 할인될 것입니다. 그리고 이 기간 동안 시즌권은 단 75달러에 판매될 것입니다. 이제, 저를 따라오시면 제가 기꺼이 무대와 무대 뒤 공간의 간략한 투어를 제공해드리겠습니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test01_92-94.mp3", "qs": [{"n": 92, "q": "What does the speaker mean when he says, \"I had a brief discussion with our CEO yesterday\"?", "opts": ["A process has been improved.", "An idea has been adopted.", "An outing will be postponed.", "A clothing line will be unveiled."], "ans": 1, "ko": "화자는 \"어제 저는 우리의 최고 경영자와 간략한 논의를 하였습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 93, "q": "What is included in the document?", "opts": ["The dates of an event", "The cost of a uniform", "The details of a policy", "The size of an order"], "ans": 2, "ko": "문서에는 무엇이 포함되어 있는가?"}, {"n": 94, "q": "What does the speaker suggest doing?", "opts": ["Waiting to get some feedback", "Directing inquiries to an assistant", "Registering for some training", "Dressing up for an important event"], "ans": 1, "ko": "화자는 무엇을 하라고 제안하는가?"}], "script": [{"sp": "M", "en": "Before we wrap up, I have one more thing to mention. Recently, many employees have discussed the idea of wearing more comfortable clothes at the office. I had a brief discussion with our CEO yesterday. Jeans and casual button-up shirts will be permitted on Thursdays and Fridays throughout the year. However, everyone has to read this document explaining the updated dress code. It must be signed and submitted by staff before the end of the week. Regarding questions that aren't addressed in the form, I suggest contacting my administrative assistant at her extension.", "ko": "우리가 회의를 마무리하기 전에, 한 가지 더 언급할 것이 있습니다. 최근에, 많은 직원들이 사무실에서 더 편안한 옷을 입는 것에 대한 의견을 논의했습니다. 어제 저는 우리의 최고 경영자와 간략한 논의를 하였습니다. 청바지와 간편한 셔츠가 목요일과 금요일마다 연중 내내 허용될 것입니다. 하지만, 모두가 업데이트된 복장 규정을 설명하고 있는 이 문서를 읽어야만 합니다. 이것은 이번 주말까지 직원들에 의해 서명된 뒤 제출되어야만 합니다. 문서에서 다루고 있지 않은 질문들에 관해서는, 저의 행정 비서에게 그녀의 내선으로 연락하는 것을 제안드립니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "Am", "audio": "Test01_95-97.mp3", "qs": [{"n": 95, "q": "What are the listeners asked to do?", "opts": ["Assist with a presentation", "Refer to a handout", "Share their opinions", "Write down some notes"], "ans": 1, "ko": "청자들은 무엇을 하도록 요청받는가?\n(A) 발표를 돕는다.\n(B) 유인물을 참고한다.\n(C) 의견을 공유한다.\n(D) 메모를 적는다."}, {"n": 96, "q": "Look at the graphic. Which show is going to be discontinued?", "opts": ["Game of Chance", "Friends of Mine", "Denver United", "Family Together"], "ans": 2, "ko": "시각 자료를 보시오. 어떤 프로그램이 중단될 것인가?\n(A) 확률 게임\n(B) 나의 친구들\n(C) 덴버 유나이티드\n(D) 가족과 함께"}, {"n": 97, "q": "What will probably happen in two weeks?", "opts": ["A business decision will be announced.", "A television show will begin filming.", "An actress will join a program.", "A study on ratings will be finished."], "ans": 0, "ko": "2주 후에 무슨 일이 일어날 것 같은가?\n(A) 사업상의 결정이 발표될 것이다.\n(B) 텔레비전 프로그램의 촬영을 시작할 것이다.\n(C) 여배우가 프로그램에 합류할 것이다.\n(D) 시청률에 대한 조사가 완료될 것이다."}], "script": [{"sp": "1", "en": "For the next part of my presentation, I'm going to discuss our television station's Monday evening lineup. Please look at the report I distributed a few minutes ago as it features graphs about our programs. Like last year, our two top-rated shows are performing well. We expect that to continue next quarter. As for our two worst-performing shows, we believe the ratings for Family Together will climb now that Cindy Carlyle has been added to the cast. Conversely, we're less optimistic about the other program. That's why we've decided to cancel it at the end of the season. Our decision will be made public at the end of the fiscal year, which is two weeks away.", "ko": "제 발표의 다음 부분으로, 저희 텔레비전 방송사의 월요일 저녁 프로그램 편성표에 대해 논의할 것입니다. 보고서에 저희의 프로그램에 대한 그래프의 특징이 나타나 있으므로 제가 몇 분 전에 나눠드린 보고서를 봐 주십시오. 작년과 같이, 저희의 가장 인기 있는 두 개의 프로그램은 잘 되고 있습니다. 다음 분기에도 이것이 계속될 것으로 예상합니다. 가장 인기가 없는 두 개의 프로그램에 대해 말하자면, Cindy Carlyle이 배역에 추가되었기 때문에 가족과 함께의 시청률은 오를 것으로 생각합니다. 반대로, 나머지 한 개의 프로그램에 대해서는 덜 낙관적입니다. 그게 바로 시즌 마지막에 그것을 취소하기로 결정한 이유입니다. 저희의 결정 사항은 2주 후인 회계 연도 말에 공표될 예정입니다."}], "gimg": "hk_t1_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "Br", "audio": "Test01_98-100.mp3", "qs": [{"n": 98, "q": "Why did an event location change?", "opts": ["A venue's rent is too high.", "Additional seating is needed.", "Parking options are insufficient.", "A building has been damaged."], "ans": 3, "ko": "행사의 장소는 왜 변경되었는가?\n(A) 장소 임대료가 너무 비싸다.\n(B) 추가 좌석이 필요하다.\n(C) 주차 선택권이 충분하지 않다.\n(D) 건물이 손상되었다."}, {"n": 99, "q": "Look at the graphic. Which entrance must attendees use?", "opts": ["Entrance A", "Entrance B", "Entrance C", "Entrance D"], "ans": 1, "ko": "시각 자료를 보시오. 참석자들은 어느 입구를 사용해야만 하는가?\n(A) 입구 A\n(B) 입구 B\n(C) 입구 C\n(D) 입구 D"}, {"n": 100, "q": "What feature of Calypso Restaurant is mentioned?", "opts": ["Extended hours", "Catering services", "An outdoor seating area", "A special summer menu"], "ans": 2, "ko": "Calypso 식당의 어떤 특징이 언급되는가?\n(A) 연장된 영업시간\n(B) 출장 음식 서비스\n(C) 야외 좌석 구역\n(D) 여름 특별 메뉴"}], "script": [{"sp": "1", "en": "It's time for a local news update. Wibley Stadium sustained numerous broken windows during Wednesday night's storm. As a result, organizers have been forced to relocate the Summerfun Volleyball Tournament to a new facility. The competition is now going to be hosted at the Clark Sports Arena on Saturday. Tickets are still available online or at the arena ticket booth. Please be advised that the arena will only be accessible via the entrance on Ontario Street for this event due to ongoing road construction. Also, Calypso Restaurant will be hosting an official outdoor viewing event of the competition on its patio for customers. OK, up next is another long stretch of music.", "ko": "최신 지역 뉴스 시간입니다. Wibley 경기장이 수요일 밤의 폭풍우 동안 많은 창문들이 깨지는 피해를 입었습니다. 그 결과, 주최자들은 Summerfun 배구 시합을 새로운 시설로 이동시킬 수밖에 없었습니다. 이 경기는 이제 토요일에 Clark 운동 경기장에서 열릴 예정입니다. 티켓들은 온라인이나 경기장 매표소에서 여전히 구매 가능합니다. 계속 진행 중인 도로 공사로 인해 이 행사를 위해 Ontario가에 있는 입구를 통해서만 경기장에 입장할 수 있음을 알고 계십시오. 또한, Calypso 식당은 손님들을 위해 공식적인 경기 야외 관람 행사를 테라스에서 주최할 것입니다. 자, 다음은 다시 장시간에 걸친 음악이 이어지겠습니다."}], "gimg": "hk_t1_g98.jpg"}]};
